sql:
SELECT description
FROM networks
WHERE type = 'social';

SELECT c.centrality_id, c.centrality_index, c.centrality_dummy, n.type
FROM centrality c
INNER JOIN networks n ON c.network_id = n.network_id;

SELECT AVG(centrality_index) AS average_degree_centrality
FROM centrality
WHERE type = 'degree';

SELECT network_id
FROM assortativity
WHERE assortativity_valence < 0;

SELECT AVG(degree) AS average_degree
FROM nodes
WHERE network_id = 0;

SELECT AVG(weight) AS average_edge_weight
FROM edges
WHERE network_id = 1;

SELECT network_id, num_nodes AS total_nodes
FROM metrics
GROUP BY network_id;

SELECT type, description
FROM networks
WHERE network_id = 1;

SELECT *
FROM networks
WHERE transitivity = (SELECT MAX(transitivity) FROM networks);

SELECT network_id
FROM networks
WHERE mean_distance_undirected = (
    SELECT MAX(mean_distance_undirected)
    FROM networks
);

SELECT n.description
FROM networks n
WHERE n.density = (SELECT MAX(density) FROM networks);
